const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;

const rawQuery = payload.query;
if (typeof rawQuery !== 'string' || rawQuery.trim() === '') {
  throw new Error('Request body must include a string field named query.');
}

let projectSlug = null;
if (payload.project_slug !== undefined && payload.project_slug !== null) {
  if (typeof payload.project_slug !== 'string') {
    throw new Error('project_slug must be a string when provided');
  }

  const trimmed = payload.project_slug.trim();
  projectSlug = trimmed || null;
}

return [{
  json: {
    query: rawQuery.trim(),
    projectSlug
  }
}];

const base = $('Normalize Input').first().json;
const rows = $input.all().map(item => item.json ?? {});

if (!base.projectSlug) {
  return [{ json: base }];
}

const firstRow = rows[0] ?? {};

const isValid =
  firstRow.project_slug_valid === true ||
  firstRow.project_slug === base.projectSlug;

if (!isValid) {
  throw new Error(`Unknown project_slug: ${base.projectSlug}`);
}

return [{ json: base }];

const base = $('Enforce Project Validation Code').first().json;
const embeddings = $json.embeddings;

if (!Array.isArray(embeddings) || !Array.isArray(embeddings[0])) {
  throw new Error('Ollama response did not contain embeddings[0].');
}

const vector = embeddings[0];
const vectorLiteral = `[${vector.join(',')}]`;

return [{
  json: {
    query: base.query,
    projectSlug: base.projectSlug,
    vector_literal: vectorLiteral
  }
}];

const base = $('Enforce Project Validation Code').first().json;
const rows = $input.all().map(item => item.json ?? {});

const relevanceThreshold = 0.50;

const memories = rows
  .map((row) => {
    const metadata = row.metadata_json && typeof row.metadata_json === 'object' ? row.metadata_json : {};
    const memoryProjectSlug = typeof metadata.project_slug === 'string' && metadata.project_slug.trim() !== ''
      ? metadata.project_slug.trim()
      : null;
    const similarity = Number(row.similarity);

    return {
      id: row.id,
      title: row.title ?? '',
      category: row.category ?? '',
      source: row.source ?? '',
      content: row.content ?? '',
      similarity,
      projectSlug: memoryProjectSlug,
      metadata_json: metadata
    };
  })
  .filter((memory) => Number.isFinite(memory.similarity) && memory.similarity >= relevanceThreshold);

const contextBlock = memories.length
  ? memories.map((memory, index) => {
      const lines = [
        `Memory ${index + 1}`,
        `Title: ${memory.title}`,
        `Category: ${memory.category}`,
        `Source: ${memory.source}`
      ];

      if (memory.projectSlug) {
        lines.push(`Project: ${memory.projectSlug}`);
      }

      lines.push('Content:');
      lines.push(memory.content);

      return lines.join('\n');
    }).join('\n\n')
  : '';

const prompt = memories.length
  ? [
      'You are answering a user question using only the supplied OpenBrain memory context.',
      'Do not fabricate facts.',
      'If the memory context is insufficient, say so clearly.',
      'Keep the answer focused and concise.',
      '',
      `User question:\n${base.query}`,
      '',
      `Memory context:\n${contextBlock}`,
      '',
      'Answer:'
    ].join('\n')
  : '';

return [{
  json: {
    query: base.query,
    projectSlug: base.projectSlug,
    memoryCount: memories.length,
    contextBlock,
    memories,
    prompt,
    noRelevantMemory: memories.length === 0
  }
}];

const item = $input.first().json;

if (Number(item.memoryCount ?? 0) <= 0) {
  return [{
    json: {
      query: item.query,
      projectSlug: item.projectSlug ?? null,
      memoryCount: 0,
      contextBlock: '',
      answer: 'No relevant memory context was found for this question.',
      memories: [],
      skipGeneration: true
    }
  }];
}

return [{
  json: {
    ...item,
    skipGeneration: false
  }
}];

const input = $input.first().json;

if (input.skipGeneration === true) {
  return [{
    json: {
      query: input.query,
      projectSlug: input.projectSlug ?? null,
      memoryCount: 0,
      contextBlock: '',
      answer: input.answer,
      memories: Array.isArray(input.memories) ? input.memories : []
    }
  }];
}

const base = $('Decide Generation Path').first().json;
let answer = typeof input.response === 'string' ? input.response.trim() : '';

if (!answer) {
  answer = 'I do not have enough memory context to answer confidently.';
}

return [{
  json: {
    query: base.query,
    projectSlug: base.projectSlug,
    memoryCount: base.memoryCount,
    contextBlock: base.contextBlock,
    answer,
    memories: base.memories
  }
}];
